const BLOCK_PREMIUM = 60;

const isBlock = (items: Item[]): boolean =>
  items.length === 3 && items.every((item) => item.type === items[0].type);

const quotePremium = (items: Item[]): number => {
  const basePremium = isBlock(items)
    ? BLOCK_PREMIUM
    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
  return basePremium + firstInsuranceSurcharge(basePremium) + PROCESSING_FEE;
};
